import requests, time, statistics
base='http://localhost:5003/login'

def avg_time(username, password='x', n=8):
    times=[]
    for _ in range(n):
        t0=time.time()
        r=requests.post(base, data={'username':username,'password':password}, allow_redirects=False)
        t1=time.time()
        times.append(t1-t0)
    return statistics.mean(times), statistics.pstdev(times)

for u in ['admin','nosuchuser123','test','root']:
    m,s=avg_time(u)
    print(u, 'avg', round(m,4), 'std', round(s,4))
